   385|function parseStoredLogContent(content: string): RunLogChunk[] {
   386|  const parsed: RunLogChunk[] = [];
   387|  for (const line of content.split("\n")) {
   388|    const trimmed = line.trim();
   389|    if (!trimmed) continue;
   390|    try {
   391|      const raw = JSON.parse(trimmed) as { ts?: unknown; stream?: unknown; chunk?: unknown };
   392|      const stream =
   393|        raw.stream === "stderr" || raw.stream === "system" ? raw.stream : "stdout";
   394|      const chunk = typeof raw.chunk === "string" ? raw.chunk : "";
   395|      const ts = typeof raw.ts === "string" ? raw.ts : new Date().toISOString();
   396|      if (!chunk) continue;
   397|      parsed.push({ ts, stream, chunk });
   398|    } catch {
   399|      // Ignore malformed log lines.
   400|    }
   401|  }
   402|  return parsed;
   403|}
