   145|function fileBaseName(filename: string) {
   146|  return filename.replace(/\.[^.]+$/, "");
   147|}
   148|
   149|function slugifyDocumentKey(input: string) {
   150|  const slug = input
   151|    .trim()
   152|    .toLowerCase()
   153|    .replace(/[^a-z0-9]+/g, "-")
   154|    .replace(/^-+|-+$/g, "");
   155|  return slug || "document";
   156|}
   157|
   158|function titleizeFilename(input: string) {
   159|  return input
   160|    .split(/[-_ ]+/g)
   161|    .filter(Boolean)
   162|    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
   163|    .join(" ");
   164|}
   165|
   166|function mergeOptimisticFeedbackVote(
   167|  previousVotes: FeedbackVote[] | undefined,
   168|  nextVote: {
   169|    issueId: string;
   170|    targetType: "issue_comment" | "issue_document_revision";
   171|    targetId: string;
   172|    vote: "up" | "down";
   173|    reason?: string;
   174|  },
   175|  currentUserId: string | null,
   176|): FeedbackVote[] {
   177|  const now = new Date();
   178|  const existingVotes = previousVotes ?? [];
   179|  const existingIndex = existingVotes.findIndex(
   180|    (feedbackVote) =>
   181|      feedbackVote.targetType === nextVote.targetType &&
   182|      feedbackVote.targetId === nextVote.targetId &&
   183|      (!currentUserId || feedbackVote.authorUserId === currentUserId),
   184|  );
   185|
   186|  if (existingIndex >= 0) {
   187|    const existingVote = existingVotes[existingIndex]!;
   188|    const updatedVote: FeedbackVote = {
   189|      ...existingVote,
   190|      vote: nextVote.vote,
   191|      reason:
   192|        nextVote.reason !== undefined
   193|          ? nextVote.reason.trim() || null
   194|          : existingVote.reason,
   195|      updatedAt: now,
   196|    };
   197|    const nextVotes = [...existingVotes];
   198|    nextVotes[existingIndex] = updatedVote;
   199|    return nextVotes;
   200|  }
