    23|
    24|export function Activity() {
    25|  const { selectedCompanyId } = useCompany();
    26|  const { setBreadcrumbs } = useBreadcrumbs();
    27|  const [filter, setFilter] = useState("all");
    28|
    29|  useEffect(() => {
    30|    setBreadcrumbs([{ label: "Activity" }]);
    31|  }, [setBreadcrumbs]);
    32|
    33|  const { data, isLoading, error } = useQuery({
    34|    queryKey: queryKeys.activity(selectedCompanyId!),
    35|    queryFn: () => activityApi.list(selectedCompanyId!),
    36|    enabled: !!selectedCompanyId,
    37|  });
    38|
    39|  const { data: agents } = useQuery({
    40|    queryKey: queryKeys.agents.list(selectedCompanyId!),
    41|    queryFn: () => agentsApi.list(selectedCompanyId!),
    42|    enabled: !!selectedCompanyId,
    43|  });
    44|
    45|  const { data: issues } = useQuery({
    46|    queryKey: queryKeys.issues.list(selectedCompanyId!),
    47|    queryFn: () => issuesApi.list(selectedCompanyId!),
    48|    enabled: !!selectedCompanyId,
    49|  });
    50|
    51|  const { data: projects } = useQuery({
    52|    queryKey: queryKeys.projects.list(selectedCompanyId!),
    53|    queryFn: () => projectsApi.list(selectedCompanyId!),
    54|    enabled: !!selectedCompanyId,
    55|  });
    56|
    57|  const { data: goals } = useQuery({
    58|    queryKey: queryKeys.goals.list(selectedCompanyId!),
    59|    queryFn: () => goalsApi.list(selectedCompanyId!),
    60|    enabled: !!selectedCompanyId,
    61|  });
    62|
    63|  const agentMap = useMemo(() => {
    64|    const map = new Map<string, Agent>();
    65|    for (const a of agents ?? []) map.set(a.id, a);
    66|    return map;
    67|  }, [agents]);
    68|
    69|  const entityNameMap = useMemo(() => {
    70|    const map = new Map<string, string>();
    71|    for (const i of issues ?? []) map.set(`issue:${i.id}`, i.identifier ?? i.id.slice(0, 8));
    72|    for (const a of agents ?? []) map.set(`agent:${a.id}`, a.name);
    73|    for (const p of projects ?? []) map.set(`project:${p.id}`, p.name);
    74|    for (const g of goals ?? []) map.set(`goal:${g.id}`, g.title);
    75|    return map;
    76|  }, [issues, agents, projects, goals]);
    77|
    78|  const entityTitleMap = useMemo(() => {
    79|    const map = new Map<string, string>();
    80|    for (const i of issues ?? []) map.set(`issue:${i.id}`, i.title);
    81|    return map;
    82|  }, [issues]);
    83|
    84|  if (!selectedCompanyId) {
    85|    return <EmptyState icon={History} message="Select a company to view activity." />;
    86|  }
    87|
    88|  if (isLoading) {
    89|    return <PageSkeleton variant="list" />;
    90|  }
    91|
    92|  const filtered =
    93|    data && filter !== "all"
    94|      ? data.filter((e) => e.entityType === filter)
    95|      : data;
    96|
    97|  const entityTypes = data
    98|    ? [...new Set(data.map((e) => e.entityType))].sort()
    99|    : [];
   100|
   101|  return (
   102|    <div className="space-y-4">
   103|      <div className="flex items-center justify-end">
   104|        <Select value={filter} onValueChange={setFilter}>
   105|          <SelectTrigger className="w-[140px] h-8 text-xs">
   106|            <SelectValue placeholder="Filter by type" />
   107|          </SelectTrigger>
   108|          <SelectContent>
   109|            <SelectItem value="all">All types</SelectItem>
   110|            {entityTypes.map((type) => (
   111|              <SelectItem key={type} value={type}>
   112|                {type.charAt(0).toUpperCase() + type.slice(1)}
   113|              </SelectItem>
   114|            ))}
   115|          </SelectContent>
   116|        </Select>
   117|      </div>
   118|
   119|      {error && <p className="text-sm text-destructive">{error.message}</p>}
   120|
   121|      {filtered && filtered.length === 0 && (
   122|        <EmptyState icon={History} message="No activity yet." />
   123|      )}
   124|
   125|      {filtered && filtered.length > 0 && (
   126|        <div className="border border-border divide-y divide-border">
   127|          {filtered.map((event) => (
   128|            <ActivityRow
   129|              key={event.id}
   130|              event={event}
   131|              agentMap={agentMap}
   132|              entityNameMap={entityNameMap}
   133|              entityTitleMap={entityTitleMap}
   134|            />
   135|          ))}
   136|        </div>
   137|      )}
   138|    </div>
   139|  );
   140|}
