{"content": "     1|import { useEffect, useRef, useState, useMemo, useCallback } from "react";
     2|import { Link, useNavigate } from "@/lib/router";
     3|import { useQuery } from "@tanstack/react-query";
     4|import { agentsApi, type OrgNode } from "../api/agents";
     5|import { useCompany } from "../context/CompanyContext";
     6|import { useBreadcrumbs } from "../context/BreadcrumbContext";
     7|import { queryKeys } from "../lib/queryKeys";
     8|import { agentUrl } from "../lib/utils";
     9|import { Button } from "@/components/ui/button";
    10|import { EmptyState } from "../components/EmptyState";
    11|import { PageSkeleton } from "../components/PageSkeleton";
    12|import { AgentIcon } from "../components/AgentIconPicker";
    13|import { Download, Network, Upload } from "lucide-react";
    14|import { AGENT_ROLE_LABELS, type Agent } from "@paperclipai/shared";
    15|
    16|// Layout constants
    17|const CARD_W = 200;
    18|const CARD_H = 100;
    19|const GAP_X = 32;
    20|const GAP_Y = 80;
    21|const PADDING = 60;
    22|
    23|// ── Tree layout types ───────────────────────────────────────────────────
    24|
    25|interface LayoutNode {
    26|  id: string;
    27|  name: string;
    28|  role: string;
    29|  status: string;
    30|  x: number;
    31|  y: number;
    32|  children: LayoutNode[];
    33|}
    34|
    35|// ── Layout algorithm ────────────────────────────────────────────────────
    36|
    37|/** Compute the width each subtree needs. */
    38|function subtreeWidth(node: OrgNode): number {
    39|  if (node.reports.length === 0) return CARD_W;
    40|  const childrenW = node.reports.reduce((sum, c) => sum + subtreeWidth(c), 0);
    41|  const gaps = (node.reports.length - 1) * GAP_X;
    42|  return Math.max(CARD_W, childrenW + gaps);
    43|}
    44|
    45|/** Recursively assign x,y positions. */
    46|function layoutTree(node: OrgNode, x: number, y: number): LayoutNode {
    47|  const totalW = subtreeWidth(node);
    48|  const layoutChildren: LayoutNode[] = [];
    49|
    50|  if (node.reports.length > 0) {
    51|    const childrenW = node.reports.reduce((sum, c) => sum + subtreeWidth(c), 0);
    52|    const gaps = (node.reports.length - 1) * GAP_X;
    53|    let cx = x + (totalW - childrenW - gaps) / 2;
    54|
    55|    for (const child of node.reports) {
    56|      const cw = subtreeWidth(child);
    57|      layoutChildren.push(layoutTree(child, cx, y + CARD_H + GAP_Y));
    58|      cx += cw + GAP_X;
    59|    }
    60|  }
    61|
    62|  return {
    63|    id: node.id,
    64|    name: node.name,
    65|    role: node.role,
    66|    status: node.status,
    67|    x: x + (totalW - CARD_W) / 2,
    68|    y,
    69|    children: layoutChildren,
    70|  };
    71|}
    72|
    73|/** Layout all root nodes side by side. */
    74|function layoutForest(roots: OrgNode[]): LayoutNode[] {
    75|  if (roots.length === 0) return [];
    76|
    77|  const totalW = roots.reduce((sum, r) => sum + subtreeWidth(r), 0);
    78|  const gaps = (roots.length - 1) * GAP_X;
    79|  let x = PADDING;
    80|  const y = PADDING;
    81|
    82|  const result: LayoutNode[] = [];
    83|  for (const root of roots) {
    84|    const w = subtreeWidth(root);
    85|    result.push(layoutTree(root, x, y));
    86|    x += w + GAP_X;
    87|  }
    88|
    89|  // Compute bounds and return
    90|  return result;
    91|}
    92|
    93|/** Flatten layout tree to list of nodes. */
    94|function flattenLayout(nodes: LayoutNode[]): LayoutNode[] {
    95|  const result: LayoutNode[] = [];
    96|  function walk(n: LayoutNode) {
    97|    result.push(n);
    98|    n.children.forEach(walk);
    99|  }
   100|  nodes.forEach(walk);
   101|  return result;
   102|}
   103|
   104|/** Collect all parent→child edges. */
   105|function collectEdges(nodes: LayoutNode[]): Array<{ parent: LayoutNode; child: LayoutNode }> {
   106|  const edges: Array<{ parent: LayoutNode; child: LayoutNode }> = [];
   107|  function walk(n: LayoutNode) {
   108|    for (const c of n.children) {
   109|      edges.push({ parent: n, child: c });
   110|      walk(c);
   111|    }
   112|  }
   113|  nodes.forEach(walk);
   114|  return edges;
   115|}
   116|
   117|// ── Status dot colors (raw hex for SVG) ─────────────────────────────────
   118|
   119|import { getAdapterLabel } from "../adapters/adapter-display-registry";
   120|
   121|const statusDotColor: Record<string, string> = {
   122|  running: "#22d3ee",
   123|  active: "#4ade80",
   124|  paused: "#facc15",
   125|  idle: "#facc15",
   126|  error: "#f87171",
   127|  terminated: "#a3a3a3",
   128|};
   129|const defaultDotColor = "#a3a3a3";
   130|
   131|// ── Main component ──────────────────────────────────────────────────────
   132|
   133|export function OrgChart() {
   134|  const { selectedCompanyId } = useCompany();
   135|  const { setBreadcrumbs } = useBreadcrumbs();
   136|  const navigate = useNavigate();
   137|
   138|  const { data: orgTree, isLoading } = useQuery({
   139|    queryKey: queryKeys.org(selectedCompanyId!),
   140|    queryFn: () => agentsApi.org(selectedCompanyId!),
   141|    enabled: !!selectedCompanyId,
   142|  });
   143|
   144|  const { data: agents } = useQuery({
   145|    queryKey: queryKeys.agents.list(selectedCompanyId!),
   146|    queryFn: () => agentsApi.list(selectedCompanyId!),
   147|    enabled: !!selectedCompanyId,
   148|  });
   149|
   150|  const agentMap = useMemo(() => {
   151|    const m = new Map<string, Agent>();
   152|    for (const a of agents ?? []) m.set(a.id, a);
   153|    return m;
   154|  }, [agents]);
   155|
   156|  useEffect(() => {
   157|    setBreadcrumbs([{ label: "Org Chart" }]);
   158|  }, [setBreadcrumbs]);
   159|
   160|  // Layout computation
   161|  const layout = useMemo(() => layoutForest(orgTree ?? []), [orgTree]);
   162|  const allNodes = useMemo(() => flattenLayout(layout), [layout]);
   163|  const edges = useMemo(() => collectEdges(layout), [layout]);
   164|
   165|  // Compute SVG bounds
   166|  const bounds = useMemo(() => {
   167|    if (allNodes.length === 0) return { width: 800, height: 600 };
   168|    let maxX = 0, maxY = 0;
   169|    for (const n of allNodes) {
   170|      maxX = Math.max(maxX, n.x + CARD_W);
   171|      maxY = Math.max(maxY, n.y + CARD_H);
   172|    }
   173|    return { width: maxX + PADDING, height: maxY + PADDING };
   174|  }, [allNodes]);
   175|
   176|  // Pan & zoom state
   177|  const containerRef = useRef<HTMLDivElement>(null);
   178|  const [pan, setPan] = useState({ x: 0, y: 0 });
   179|  const [zoom, setZoom] = useState(1);
   180|  const [dragging, setDragging] = useState(false);
   181|  const dragStart = useRef({ x: 0, y: 0, panX: 0, panY: 0 });
   182|
   183|  // Center the chart on first load
   184|  const hasInitialized = useRef(false);
   185|  useEffect(() => {
   186|    if (hasInitialized.current || allNodes.length === 0 || !containerRef.current) return;
   187|    hasInitialized.current = true;
   188|
   189|    const container = containerRef.current;
   190|    const containerW = container.clientWidth;
   191|    const containerH = container.clientHeight;
   192|
   193|    // Fit chart to container
   194|    const scaleX = (containerW - 40) / bounds.width;
   195|    const scaleY = (containerH - 40) / bounds.height;
   196|    const fitZoom = Math.min(scaleX, scaleY, 1);
   197|
   198|    const chartW = bounds.width * fitZoom;
   199|    const chartH = bounds.height * fitZoom;
   200|
   201|    setZoom(fitZoom);
   202|    setPan({
   203|      x: (containerW - chartW) / 2,
   204|      y: (containerH - chartH) / 2,
   205|    });
   206|  }, [allNodes, bounds]);
   207|
   208|  const handleMouseDown = useCallback((e: React.MouseEvent) => {
   209|    if (e.button !== 0) return;
   210|    // Don't drag if clicking a card
   211|    const target = e.target as HTMLElement;
   212|    if (target.closest("[data-org-card]")) return;
   213|    setDragging(true);
   214|    dragStart.current = { x: e.clientX, y: e.clientY, panX: pan.x, panY: pan.y };
   215|  }, [pan]);
   216|
   217|  const handleMouseMove = useCallback((e: React.MouseEvent) => {
   218|    if (!dragging) return;
   219|    const dx = e.clientX - dragStart.current.x;
   220|    const dy = e.clientY - dragStart.current.y;
   221|    setPan({ x: dragStart.current.panX + dx, y: dragStart.current.panY + dy });
   222|  }, [dragging]);
   223|
   224|  const handleMouseUp = useCallback(() => {
   225|    setDragging(false);
   226|  }, []);
   227|
   228|  const handleWheel = useCallback((e: React.WheelEvent) => {
   229|    e.preventDefault();
   230|    const container = containerRef.current;
   231|    if (!container) return;
   232|
   233|    const rect = container.getBoundingClientRect();
   234|    const mouseX = e.clientX - rect.left;
   235|    const mouseY = e.clientY - rect.top;
   236|
   237|    const factor = e.deltaY < 0 ? 1.1 : 0.9;
   238|    const newZoom = Math.min(Math.max(zoom * factor, 0.2), 2);
   239|
   240|    // Zoom toward mouse position
   241|    const scale = newZoom / zoom;
   242|    setPan({
   243|      x: mouseX - scale * (mouseX - pan.x),
   244|      y: mouseY - scale * (mouseY - pan.y),
   245|    });
   246|    setZoom(newZoom);
   247|  }, [zoom, pan]);
   248|
   249|  if (!selectedCompanyId) {
   250|    return <EmptyState icon={Network} message="Select a company to view the org chart." />;
   251|  }
   252|
   253|  if (isLoading) {
   254|    return <PageSkeleton variant="org-chart" />;
   255|  }
   256|
   257|  if (orgTree && orgTree.length === 0) {
   258|    return <EmptyState icon={Network} message="No organizational hierarchy defined." />;
   259|  }
   260|
   261|  return (
   262|    <div className="flex flex-col h-full">
   263|    <div className="mb-2 flex items-center justify-start gap-2 shrink-0">
   264|      <Link to="/company/import">
   265|        <Button variant="outline" size="sm">
   266|          <Upload className="mr-1.5 h-3.5 w-3.5" />
   267|          Import company
   268|        </Button>
   269|      </Link>
   270|      <Link to="/company/export">
   271|        <Button variant="outline" size="sm">
   272|          <Download className="mr-1.5 h-3.5 w-3.5" />
   273|          Export company
   274|        </Button>
   275|      </Link>
   276|    </div>
   277|    <div
   278|      ref={containerRef}
   279|      className="w-full flex-1 min-h-0 overflow-hidden relative bg-muted/20 border border-border rounded-lg"
   280|      style={{ cursor: dragging ? "grabbing" : "grab" }}
   281|      onMouseDown={handleMouseDown}
   282|      onMouseMove={handleMouseMove}
   283|      onMouseUp={handleMouseUp}
   284|      onMouseLeave={handleMouseUp}
   285|      onWheel={handleWheel}
   286|    >
   287|      {/* Zoom controls */}
   288|      <div className="absolute top-3 right-3 z-10 flex flex-col gap-1">
   289|        <button
   290|          className="w-7 h-7 flex items-center justify-center bg-background border border-border rounded text-sm hover:bg-accent transition-colors"
   291|          onClick={() => {
   292|            const newZoom = Math.min(zoom * 1.2, 2);
   293|            const container = containerRef.current;
   294|            if (container) {
   295|              const cx = container.clientWidth / 2;
   296|              const cy = container.clientHeight / 2;
   297|              const scale = newZoom / zoom;
   298|              setPan({ x: cx - scale * (cx - pan.x), y: cy - scale * (cy - pan.y) });
   299|            }
   300|            setZoom(newZoom);
   301|          }}
   302|          aria-label="Zoom in"
   303|        >
   304|          +
   305|        </button>
   306|        <button
   307|          className="w-7 h-7 flex items-center justify-center bg-background border border-border rounded text-sm hover:bg-accent transition-colors"
   308|          onClick={() => {
   309|            const newZoom = Math.max(zoom * 0.8, 0.2);
   310|            const container = containerRef.current;
   311|            if (container) {
   312|              const cx = container.clientWidth / 2;
   313|              const cy = container.clientHeight / 2;
   314|              const scale = newZoom / zoom;
   315|              setPan({ x: cx - scale * (cx - pan.x), y: cy - scale * (cy - pan.y) });
