   329|            const scaleX = (cW - 40) / bounds.width;
   330|            const scaleY = (cH - 40) / bounds.height;
   331|            const fitZoom = Math.min(scaleX, scaleY, 1);
   332|            const chartW = bounds.width * fitZoom;
   333|            const chartH = bounds.height * fitZoom;
   334|            setZoom(fitZoom);
   335|            setPan({ x: (cW - chartW) / 2, y: (cH - chartH) / 2 });
   336|          }}
   337|          title="Fit to screen"
   338|          aria-label="Fit chart to screen"
   339|        >
