   351|      >
   352|        <g transform={`translate(${pan.x}, ${pan.y}) scale(${zoom})`}>
   353|          {edges.map(({ parent, child }) => {
   354|            const x1 = parent.x + CARD_W / 2;
   355|            const y1 = parent.y + CARD_H;
   356|            const x2 = child.x + CARD_W / 2;
   357|            const y2 = child.y;
