   359|
   360|            return (
   361|              <path
   362|                key={`${parent.id}-${child.id}`}
   363|                d={`M ${x1} ${y1} L ${x1} ${midY} L ${x2} ${midY} L ${x2} ${y2}`}
   364|                fill="none"
   365|                stroke="var(--border)"
   366|                strokeWidth={1.5}
   367|              />
   368|            );
   369|          })}
   370|        </g>
   371|      </svg>
   372|
   373|      {/* Card layer */}
   374|      <div
   375|        className="absolute inset-0"
   376|        style={{
   377|          transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
   378|          transformOrigin: "0 0",
   379|        }}
   380|      >
   381|        {allNodes.map((node) => {
   382|          const agent = agentMap.get(node.id);
   383|          const dotColor = statusDotColor[node.status] ?? defaultDotColor;
   384|
   385|          return (
   386|            <div
   387|              key={node.id}
