   389|              className="absolute bg-card border border-border rounded-lg shadow-sm hover:shadow-md hover:border-foreground/20 transition-[box-shadow,border-color] duration-150 cursor-pointer select-none"
   390|              style={{
   391|                left: node.x,
   392|                top: node.y,
   393|                width: CARD_W,
   394|                minHeight: CARD_H,
   395|              }}
   396|              onClick={() => navigate(agent ? agentUrl(agent) : `/agents/${node.id}`)}
   397|            >
   398|              <div className="flex items-center px-4 py-3 gap-3">
   399|                {/* Agent icon + status dot */}
   400|                <div className="relative shrink-0">
   401|                  <div className="w-9 h-9 rounded-full bg-muted flex items-center justify-center">
   402|                    <AgentIcon icon={agent?.icon} className="h-4.5 w-4.5 text-foreground/70" />
   403|                  </div>
   404|                  <span
   405|                    className="absolute -bottom-0.5 -right-0.5 h-3 w-3 rounded-full border-2 border-card"
   406|                    style={{ backgroundColor: dotColor }}
   407|                  />
   408|                </div>
   409|                {/* Name + role + adapter type */}
   410|                <div className="flex flex-col items-start min-w-0 flex-1">
   411|                  <span className="text-sm font-semibold text-foreground leading-tight">
   412|                    {node.name}
   413|                  </span>
   414|                  <span className="text-[11px] text-muted-foreground leading-tight mt-0.5">
   415|                    {agent?.title ?? roleLabel(node.role)}
   416|                  </span>
   417|                  {agent && (
   418|                    <span className="text-[10px] text-muted-foreground/60 font-mono leading-tight mt-1">
   419|                      {getAdapterLabel(agent.adapterType)}
   420|                    </span>
   421|                  )}
   422|                  {agent && agent.capabilities && (
   423|                    <span className="text-[10px] text-muted-foreground/80 leading-tight mt-1 line-clamp-2">
   424|                      {agent.capabilities}
   425|                    </span>
   426|                  )}
   427|                </div>
   428|              </div>
   429|            </div>
   430|          );
   431|        })}
   432|      </div>
   433|    </div>
   434|    </div>
   435|  );
   436|}
   437|
