{"content": "     1|import { createContext, useCallback, useContext, useState, type ReactNode } from "react";
     2|
     3|const STORAGE_KEY = "paperclip:panel-visible";
     4|
     5|interface PanelContextValue {
     6|  panelContent: ReactNode | null;
     7|  panelVisible: boolean;
     8|  openPanel: (content: ReactNode) => void;
     9|  closePanel: () => void;
    10|  setPanelVisible: (visible: boolean) => void;
    11|  togglePanelVisible: () => void;
    12|}
    13|
    14|const PanelContext = createContext<PanelContextValue | null>(null);
    15|
    16|function readPreference(): boolean {
    17|  try {
    18|    const raw = localStorage.getItem(STORAGE_KEY);
    19|    return raw === null ? true : raw === "true";
    20|  } catch {
    21|    return true;
    22|  }
    23|}
    24|
    25|function writePreference(visible: boolean) {
    26|  try {
    27|    localStorage.setItem(STORAGE_KEY, String(visible));
    28|  } catch {
    29|    // Ignore storage failures.
    30|  }
    31|}
    32|
    33|export function PanelProvider({ children }: { children: ReactNode }) {
    34|  const [panelContent, setPanelContent] = useState<ReactNode | null>(null);
    35|  const [panelVisible, setPanelVisibleState] = useState(readPreference);
    36|
    37|  const openPanel = useCallback((content: ReactNode) => {
    38|    setPanelContent(content);
    39|  }, []);
    40|
    41|  const closePanel = useCallback(() => {
    42|    setPanelContent(null);
    43|  }, []);
    44|
    45|  const setPanelVisible = useCallback((visible: boolean) => {
    46|    setPanelVisibleState(visible);
    47|    writePreference(visible);
    48|  }, []);
    49|
    50|  const togglePanelVisible = useCallback(() => {
    51|    setPanelVisibleState((prev) => {
    52|      const next = !prev;
    53|      writePreference(next);
    54|      return next;
    55|    });
    56|  }, []);
    57|
    58|  return (
    59|    <PanelContext.Provider
    60|      value={{ panelContent, panelVisible, openPanel, closePanel, setPanelVisible, togglePanelVisible }}
    61|    >
    62|      {children}
    63|    </PanelContext.Provider>
    64|  );
    65|}
    66|
    67|export function usePanel() {
    68|  const ctx = useContext(PanelContext);
    69|  if (!ctx) {
    70|    throw new Error("usePanel must be used within PanelProvider");
    71|  }
    72|  return ctx;
