     2|
     3|export class ApiError extends Error {
     4|  status: number;
     5|  body: unknown;
     6|
     7|  constructor(message: string, status: number, body: unknown) {
     8|    super(message);
     9|    this.name = "ApiError";
    10|    this.status = status;
    11|    this.body = body;
    12|  }
    13|}
    14|
    15|async function request<T>(path: string, init?: RequestInit): Promise<T> {
    16|  const headers = new Headers(init?.headers ?? undefined);
    17|  const body = init?.body;
    18|  if (!(body instanceof FormData) && !headers.has("Content-Type")) {
    19|    headers.set("Content-Type", "application/json");
    20|  }
    21|
    22|  const res = await fetch(`${BASE}${path}`, {
    23|    headers,
    24|    credentials: "include",
    25|    ...init,
    26|  });
    27|  if (!res.ok) {
    28|    const errorBody = await res.json().catch(() => null);
    29|    throw new ApiError(
    30|      (errorBody as { error?: string } | null)?.error ?? `Request failed: ${res.status}`,
    31|      res.status,
    32|      errorBody,
    33|    );
    34|  }
    35|  if (res.status === 204) return undefined as T;
    36|  return res.json();
    37|}
    38|
    39|export const api = {
    40|  get: <T>(path: string) => request<T>(path),
    41|  post: <T>(path: string, body: unknown) =>
    42|    request<T>(path, { method: "POST", body: JSON.stringify(body) }),
    43|  postForm: <T>(path: string, body: FormData) =>
    44|    request<T>(path, { method: "POST", body }),
    45|  put: <T>(path: string, body: unknown) =>
    46|    request<T>(path, { method: "PUT", body: JSON.stringify(body) }),
    47|  patch: <T>(path: string, body: unknown) =>
    48|    request<T>(path, { method: "PATCH", body: JSON.stringify(body) }),
    49|  delete: <T>(path: string) => request<T>(path, { method: "DELETE" }),
    50|};
