     2|import {
     3|  focusPageSearchShortcutTarget,
     4|  hasBlockingShortcutDialog,
     5|  isKeyboardShortcutTextInputTarget,
     6|} from "../lib/keyboardShortcuts";
     7|
     8|interface ShortcutHandlers {
     9|  enabled?: boolean;
    10|  onNewIssue?: () => void;
    11|  onSearch?: () => void;
    12|  onToggleSidebar?: () => void;
    13|  onTogglePanel?: () => void;
    14|  onShowShortcuts?: () => void;
    15|}
    16|
    17|export function useKeyboardShortcuts({
    18|  enabled = true,
    19|  onNewIssue,
    20|  onSearch,
    21|  onToggleSidebar,
    22|  onTogglePanel,
    23|  onShowShortcuts,
    24|}: ShortcutHandlers) {
    25|  useEffect(() => {
    26|    if (!enabled) return;
    27|
    28|    function handleKeyDown(e: KeyboardEvent) {
    29|      if (e.defaultPrevented) {
    30|        return;
    31|      }
    32|
    33|      // Don't fire shortcuts when typing in inputs
    34|      if (isKeyboardShortcutTextInputTarget(e.target)) {
    35|        return;
    36|      }
    37|
    38|      // / → Page search when available, otherwise quick search
    39|      if (e.key === "/" && !e.metaKey && !e.ctrlKey && !e.altKey) {
    40|        if (hasBlockingShortcutDialog()) {
    41|          return;
    42|        }
    43|
    44|        e.preventDefault();
    45|        if (!focusPageSearchShortcutTarget()) {
    46|          onSearch?.();
    47|        }
    48|        return;
    49|      }
    50|
    51|      // ? → Show keyboard shortcuts cheatsheet
    52|      if (e.key === "?" && !e.metaKey && !e.ctrlKey && !e.altKey) {
    53|        e.preventDefault();
    54|        onShowShortcuts?.();
    55|        return;
    56|      }
    57|
    58|      // C → New Issue
    59|      if (e.key === "c" && !e.metaKey && !e.ctrlKey && !e.altKey) {
    60|        e.preventDefault();
    61|        onNewIssue?.();
    62|      }
    63|
    64|      // [ → Toggle Sidebar
    65|      if (e.key === "[" && !e.metaKey && !e.ctrlKey) {
    66|        e.preventDefault();
    67|        onToggleSidebar?.();
    68|      }
    69|
    70|      // ] → Toggle Panel
    71|      if (e.key === "]" && !e.metaKey && !e.ctrlKey) {
    72|        e.preventDefault();
    73|        onTogglePanel?.();
    74|      }
    75|    }
    76|
    77|    document.addEventListener("keydown", handleKeyDown);
    78|    return () => document.removeEventListener("keydown", handleKeyDown);
    79|  }, [enabled, onNewIssue, onSearch, onToggleSidebar, onTogglePanel, onShowShortcuts]);
    80|}
